const todayISO = () => new Date().toISOString().slice(0, 10);
const dayLabel = (iso) => {
  const d = new Date(iso + "T12:00:00");
  return ["Dom", "Lun", "Mar", "Mié", "Jue", "Vie", "Sáb"][d.getDay()];
};

/* ── seed de horarios, asignaciones y gestiones (demo realista) ── */
function buildSeed() {
  const today = todayISO();
  const days = [...Array(7)].map((_, i) => {
    const d = new Date(); d.setDate(d.getDate() - (6 - i));
    return d.toISOString().slice(0, 10);
  });

  // horarios de hoy (minutos disponibles = turno - almuerzo - break)
  const horarios = {};
  TEAM_SEED.forEach((u, i) => {
    const turnos = [["06:00", "14:00", 0, 15], ["07:00", "16:00", 60, 15],
      ["08:00", "17:00", 60, 15], ["14:00", "22:00", 0, 15], ["07:30", "16:00", 60, 15]];
    const [ini, fin, alm, brk] = turnos[i % turnos.length];
    const h = (parseInt(fin) - parseInt(ini)) * 60 - alm - brk;
    horarios[u.id] = { fecha: today, ini, fin, almuerzo: alm, brk, disp: h };
  });

  // asignaciones del día (bandeja) — repartidas por el senior
  const asign = [];
  const cn = () => "0" + (10000000 + Math.floor(Math.random() * 8999999));
  const plan = { decheverri: 10, jmlara: 8, jocampo: 9, ateuta: 7, yarenas: 11, mromero: 6, cmendoza: 5, dtrivino: 8, arodriguez: 6, sulloa: 4, joviedo: 5 };
  let aid = 1;
  TEAM_SEED.forEach((u) => {
    const n = plan[u.login] || 0;
    for (let k = 0; k < n; k++) asign.push({ id: "a" + aid++, fecha: today, userId: u.id, numeroCaso: cn(), estado: "pendiente", asignadoPor: "u1" });
  });

  // gestiones — semana completa para nutrir gráficas + hoy con avance parcial
  const gest = [];
  let gid = 1;
  const pushG = (userId, fecha, gtId, caso, min, hora, asignacionId) =>
    gest.push({ id: "ge" + gid++, userId, fecha, tipoId: gtId, numeroCaso: caso, minutos: min, hora, asignacionId: asignacionId || null });

  // historial semana (días previos)
  days.slice(0, 6).forEach((f, di) => {
    TEAM_SEED.forEach((u) => {
      const base = u.rol === "senior" ? 6 : 9 + (di % 4);
      const wd = new Date(f + "T12:00:00").getDay();
      const factor = wd === 0 || wd === 6 ? 0.35 : 1; // fin de semana baja demanda
      const count = Math.round(base * factor);
      for (let k = 0; k < count; k++) {
        const gt = GESTIONES_SEED.filter((g) => !g.seniorOnly || u.rol === "senior");
        const t = gt[Math.floor(Math.random() * gt.length)];
        const min = Math.max(3, Math.round(t.umbral * (0.5 + Math.random() * 0.7)));
        pushG(u.id, f, t.id, cn(), min, "1" + (k % 8) + ":0" + (k % 6));
      }
    });
  });

  // hoy: marcar parte de la bandeja como gestionada / en progreso
  asign.forEach((a, idx) => {
    const r = Math.random();
    if (r < 0.45) {
      a.estado = "gestionado";
      const t = GESTIONES_SEED[2]; // seguimiento
      pushG(a.userId, today, t.id, a.numeroCaso, 8 + Math.floor(Math.random() * 9), "09:" + (10 + (idx % 40)), a.id);
    } else if (r < 0.62) {
      a.estado = "progreso";
      pushG(a.userId, today, GESTIONES_SEED[5].id, a.numeroCaso, 7, "10:" + (10 + (idx % 40)), a.id);
    }
  });
  // una entrada anómala para demostrar la alerta de auditoría
  pushG("u9", today, GESTIONES_SEED[2].id, "012998877", 52, "11:20");

  return { horarios, asignaciones: asign, gestiones: gest, days, today };
}

