function GestionConfig({ gestionTypes, setGestionTypes, fire }) {
  const [modal, setModal] = useState(false);
  const [nombre, setNombre] = useState(""); const [cat, setCat] = useState("casos"); const [umbral, setUmbral] = useState(15);
  const toggle = (id) => setGestionTypes((p) => p.map((g) => g.id === id ? { ...g, activo: !g.activo } : g));
  const add = () => {
    if (!nombre.trim()) return;
    setGestionTypes((p) => [...p, { id: "g" + Date.now(), nombre: nombre.toUpperCase(), cat, umbral: +umbral, activo: true, seniorOnly: false }]);
    setModal(false); setNombre(""); fire("Gestión agregada al catálogo");
  };
  return (
    <>
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: 16, display: "flex", justifyContent: "space-between", alignItems: "center", borderBottom: "1px solid var(--line)" }}>
          <div><div className="h2">Catálogo de gestiones</div><div className="sub" style={{ fontSize: 12 }}>Activa, desactiva o agrega tipos. El "tiempo típico" define cuándo se marca una alerta.</div></div>
          <button className="btn primary" onClick={() => setModal(true)}><Plus size={16} />Nueva gestión</button>
        </div>
        <div style={{ overflow: "auto", maxHeight: 480 }}>
          <table className="tbl">
            <thead><tr><th>Gestión</th><th>Categoría</th><th>Tiempo típico</th><th>Estado</th></tr></thead>
            <tbody>
              {gestionTypes.map((g) => (
                <tr key={g.id}>
                  <td style={{ fontWeight: 600 }}>{g.nombre}{g.seniorOnly && <span className="chip neutral" style={{ marginLeft: 8 }}>Senior</span>}</td>
                  <td><span style={{ display: "inline-flex", alignItems: "center", gap: 7 }}><span style={{ width: 8, height: 8, borderRadius: 3, background: CATS[g.cat].color }} />{CATS[g.cat].label}</span></td>
                  <td className="mono">{g.umbral} min</td>
                  <td>
                    <button className={"chip " + (g.activo ? "done" : "neutral")} style={{ cursor: "pointer", border: "none" }} onClick={() => toggle(g.id)}>
                      {g.activo ? <><Check size={11} />Activa</> : "Inactiva"}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      {modal && (
        <div className="overlay" onClick={() => setModal(false)}>
          <div className="modal" style={{ maxWidth: 440 }} onClick={(e) => e.stopPropagation()}>
            <div className="modalHead"><div className="h2">Nueva gestión</div><button className="xbtn" onClick={() => setModal(false)}><X size={16} /></button></div>
            <div className="modalBody">
              <label className="lbl">Nombre</label>
              <input className="inp" value={nombre} placeholder="EJ. VALIDACIÓN DE ENLACE" onChange={(e) => setNombre(e.target.value)} />
              <div className="grid" style={{ gridTemplateColumns: "1fr 1fr", marginTop: 12 }}>
                <div><label className="lbl">Categoría</label>
                  <select className="inp" value={cat} onChange={(e) => setCat(e.target.value)}>
                    {Object.entries(CATS).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}
                  </select>
                </div>
                <div><label className="lbl">Tiempo típico (min)</label><input className="inp mono" type="number" value={umbral} onChange={(e) => setUmbral(e.target.value)} /></div>
              </div>
            </div>
            <div className="modalFoot"><button className="btn ghost" onClick={() => setModal(false)}>Cancelar</button><button className="btn primary" onClick={add}>Agregar</button></div>
          </div>
        </div>
      )}
    </>
  );
}

